#!/usr/bin/env python3
"""Audit Group (issue) model dependents in the Sentry backend."""
import ast
import os
import sys
from pathlib import Path

ROOT = Path("/Users/luc/Developer/luuuc/oss/sense-benchmark/baseline/sentry/src/sentry")
RESULTS = Path("/Users/luc/Developer/luuuc/oss/sense/bench/verticals/python-django/results/kimi-for-coding_k2p7/baseline/sentry/run-scratch/opencode/group_audit.json")

FIELD_TARGET_NAMES = {"group", "group_id"}

def is_model_field_assign(target, value):
    if not isinstance(target, ast.Name):
        return False
    if target.id not in FIELD_TARGET_NAMES:
        return False
    if isinstance(value, ast.Call):
        # field constructors are Calls; any group/group_id assignment to a Call
        # in a class body is treated as a model field.
        return True
    return False

def names_in_annotation(node):
    names = set()
    if node is None:
        return names
    for child in ast.walk(node):
        if isinstance(child, ast.Name):
            names.add(child.id)
        if isinstance(child, ast.Attribute):
            names.add(child.attr)
    return names

def find_dependents(path: Path):
    deps = []
    for f in path.rglob("*.py"):
        rel = f.relative_to(path)
        # Exclude tests and migrations.
        if any(part in {"tests", "testutils", "migrations"} for part in rel.parts):
            continue
        if f.name.startswith("test_"):
            continue
        try:
            source = f.read_text()
            tree = ast.parse(source, str(f))
        except SyntaxError:
            continue

        imports_group = False
        for node in ast.walk(tree):
            if isinstance(node, ast.ImportFrom):
                if node.module == "sentry.models.group" and any(a.name == "Group" for a in node.names):
                    imports_group = True
                    deps.append((str(rel), node.lineno, "import Group"))
                if node.module == "sentry.models" and any(a.name == "Group" for a in node.names):
                    imports_group = True
                    deps.append((str(rel), node.lineno, "import Group"))

        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef):
                # Model fields inside class body
                for body_node in node.body:
                    if isinstance(body_node, ast.Assign):
                        for target in body_node.targets:
                            if is_model_field_assign(target, body_node.value):
                                deps.append((str(rel), body_node.lineno, f"model field {target.id} in {node.name}"))
                    elif isinstance(body_node, ast.AnnAssign):
                        target = body_node.target
                        if isinstance(target, ast.Name) and target.id in FIELD_TARGET_NAMES:
                            deps.append((str(rel), body_node.lineno, f"annotated field {target.id} in {node.name}"))
                        elif names_in_annotation(body_node.annotation) & {"Group"}:
                            deps.append((str(rel), body_node.lineno, f"Group annotation in {node.name}"))

            elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                # Capture parameters named group/group_id or annotated with Group
                for arg in node.args.args + node.args.posonlyargs + node.args.kwonlyargs:
                    if arg.arg in FIELD_TARGET_NAMES:
                        deps.append((str(rel), node.lineno, f"function {node.name}({arg.arg})"))
                    elif arg.annotation and "Group" in names_in_annotation(arg.annotation):
                        deps.append((str(rel), node.lineno, f"function {node.name} Group annotation"))
                # Return annotation
                if node.returns and "Group" in names_in_annotation(node.returns):
                    deps.append((str(rel), node.lineno, f"function {node.name} -> Group"))

                # Decorated task check (instrumented_task, rpc_method, etc.)
                is_task = any(
                    (isinstance(d, ast.Name) and d.id in {"instrumented_task", "task"})
                    or (isinstance(d, ast.Call) and isinstance(d.func, ast.Name) and d.func.id in {"instrumented_task", "task"})
                    for d in node.decorator_list
                )
                if is_task:
                    for arg in node.args.args + node.args.posonlyargs + node.args.kwonlyargs:
                        if arg.arg in {"group_id", "group"}:
                            deps.append((str(rel), node.lineno, f"task {node.name}({arg.arg})"))

    return deps

def main():
    deps = find_dependents(ROOT)
    # Remove exact duplicates
    unique = []
    seen = set()
    for rel, lineno, desc in deps:
        key = (rel, lineno, desc)
        if key not in seen:
            seen.add(key)
            unique.append((rel, lineno, desc))
    # Sort by file then line
    unique.sort(key=lambda x: (x[0], x[1]))

    out_lines = []
    for rel, lineno, desc in unique:
        out_lines.append(f"src/sentry/{rel}:{lineno}  {desc}")

    RESULTS.write_text("\n".join(out_lines))
    print(f"Wrote {len(out_lines)} dependents to {RESULTS}")

if __name__ == "__main__":
    main()

