#!/usr/bin/env python3
"""Audit Group (issue) model dependents in the Sentry backend."""
import ast
import os
from pathlib import Path

ROOT = Path("/Users/luc/Developer/luuuc/oss/sense-benchmark/baseline/sentry/src/sentry")
OUT = Path("/Users/luc/Developer/luuuc/oss/sense/bench/verticals/python-django/results/kimi-for-coding_k2p7/baseline/sentry/run-scratch/opencode/group_audit_v2.json")

FIELD_TARGETS = {"group", "group_id"}
ISSUE_PATHS = {"/issues/", "/api/", "/integrations/", "/notifications/", "/tasks/", "/seer/",
               "/workflow_engine/", "/incidents/", "/digests/", "/feedback/", "/replays/",
               "/deletions/", "/sentry_apps/", "/grouping/", "/eventstream/", "/event_manager.py"}
KAFKA_PATHS = {"/consumers/", "/runner/commands/run.py"}


def is_issue_path(path: str) -> bool:
    return any(p in path for p in ISSUE_PATHS) and not any(p in path for p in KAFKA_PATHS)


def is_django_model(cls: ast.ClassDef) -> bool:
    for base in cls.bases:
        if isinstance(base, ast.Name):
            if base.id.endswith("Model") or base.id in {"Model"}:
                return True
        elif isinstance(base, ast.Attribute):
            if base.attr.endswith("Model"):
                return True
        elif isinstance(base, ast.Call):
            if isinstance(base.func, ast.Name) and base.func.id.endswith("Model"):
                return True
            if isinstance(base.func, ast.Attribute) and base.func.attr.endswith("Model"):
                return True
    return False


def is_serializer(cls: ast.ClassDef) -> bool:
    for base in cls.bases:
        if isinstance(base, ast.Name) and base.id.endswith("Serializer"):
            return True
        if isinstance(base, ast.Attribute) and base.attr.endswith("Serializer"):
            return True
    return False


def is_analytics_event(cls: ast.ClassDef) -> bool:
    for base in cls.bases:
        if isinstance(base, ast.Name) and base.id == "Event":
            return True
        if isinstance(base, ast.Attribute) and base.attr == "Event":
            return True
    return False


def names_in(node):
    out = set()
    if node is None:
        return out
    for child in ast.walk(node):
        if isinstance(child, ast.Name):
            out.add(child.id)
        elif isinstance(child, ast.Attribute):
            out.add(child.attr)
    return out


def call_name(node: ast.AST) -> str | None:
    if isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            return node.func.id
        if isinstance(node.func, ast.Attribute):
            return node.func.attr
    return None


def audit():
    dependents = []
    for f in ROOT.rglob("*.py"):
        rel = f.relative_to(ROOT)
        path_str = str(f)
        if any(part in {"tests", "testutils", "migrations"} for part in rel.parts):
            continue
        if f.name.startswith("test_"):
            continue
        try:
            source = f.read_text()
            tree = ast.parse(source, str(f))
        except SyntaxError:
            continue

        imports_group = False
        for node in ast.walk(tree):
            if isinstance(node, ast.ImportFrom):
                if node.module in {"sentry.models.group", "sentry.models"} and any(a.name == "Group" for a in node.names):
                    imports_group = True
                    dependents.append((str(rel), node.lineno, "import Group", "import"))

        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef):
                model = is_django_model(node)
                serializer = is_serializer(node)
                analytics = is_analytics_event(node)

                for body in node.body:
                    target = None
                    value = None
                    if isinstance(body, ast.Assign):
                        for t in body.targets:
                            if isinstance(t, ast.Name):
                                target = t
                                value = body.value
                    elif isinstance(body, ast.AnnAssign):
                        if isinstance(body.target, ast.Name):
                            target = body.target
                            value = body.value
                    if target is None or target.id not in FIELD_TARGETS:
                        continue

                    cname = call_name(value)
                    if target.id == "group":
                        if model and cname in {"FlexibleForeignKey", "ForeignKey", "OneToOneField", "HybridCloudForeignKey"}:
                            # Confirm FK target is Group
                            if value and value.args:
                                first = value.args[0]
                                if isinstance(first, ast.Constant) and isinstance(first.value, str) and "Group" in first.value:
                                    dependents.append((str(rel), body.lineno, f"model FK group in {node.name}", "model"))
                        elif serializer:
                            # Serializer fields named group are usually not issue groups
                            pass
                        elif analytics:
                            # analytics group attributes are IDs, not objects; handled below via group_id
                            pass
                        elif "Group" in names_in(body):
                            dependents.append((str(rel), body.lineno, f"Group field/annotation in {node.name}", "data_structure"))
                    elif target.id == "group_id":
                        if analytics or model or (value is None and "Group" in names_in(body.annotation)):
                            dependents.append((str(rel), body.lineno, f"group_id field/annotation in {node.name}", "data_structure"))
                        elif model:
                            dependents.append((str(rel), body.lineno, f"model field group_id in {node.name}", "model"))

            elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                # parameters
                for arg in node.args.args + node.args.posonlyargs + node.args.kwonlyargs:
                    if arg.arg == "group":
                        if imports_group or is_issue_path(path_str):
                            dependents.append((str(rel), node.lineno, f"function {node.name}(group)", "function"))
                    elif arg.arg == "group_id":
                        # kafka/runner group_id is not an issue
                        if not any(p in path_str for p in KAFKA_PATHS) and (imports_group or is_issue_path(path_str)):
                            dependents.append((str(rel), node.lineno, f"function {node.name}(group_id)", "function"))
                    elif arg.annotation and "Group" in names_in(arg.annotation):
                        if imports_group:
                            dependents.append((str(rel), node.lineno, f"function {node.name} Group annotation", "function"))
                if node.returns and "Group" in names_in(node.returns):
                    if imports_group:
                        dependents.append((str(rel), node.lineno, f"function {node.name} -> Group", "function"))

    # deduplicate
    seen = set()
    out = []
    for rel, lineno, desc, category in dependents:
        key = (rel, lineno, desc)
        if key not in seen:
            seen.add(key)
            out.append((rel, lineno, desc, category))
    out.sort(key=lambda x: (x[0], x[1]))

    # write per-category lines
    lines = []
    for category in ["model", "data_structure", "function", "import"]:
        for rel, lineno, desc, cat in out:
            if cat == category:
                lines.append(f"src/sentry/{rel}:{lineno}  {desc}")
    OUT.write_text("\n".join(lines))
    print(f"Wrote {len(lines)} dependents to {OUT}")

if __name__ == "__main__":
    audit()

